1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteItem {
6	  type: string;
7	}
8	
9	export interface QuoteStep {
10	  op: "quote";
11	  items: QuoteItem[];
12	}
13	
14	export type Step = QuoteStep;
15	
16	export interface Scenario {
17	  customer: Customer;
18	  steps: Step[];
19	}
20	
21	export interface QuoteResult {
22	  premium: number;
23	}
24	
25	export type StepResult = QuoteResult;
26	
27	export interface ScenarioResult {
28	  results: StepResult[];
29	}
30	
31	const basePremiums: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	};
38	
39	const PROCESSING_FEE = 5;
40	
41	export function runScenario(scenario: Scenario): ScenarioResult {
42	  const results = scenario.steps.map((step) => {
43	    const base = basePremiums[step.items[0].type];
44	    return { premium: base + PROCESSING_FEE };
45	  });
46	  return { results };
47	}
